# Prompt strategy comparison — Staff-level cost-benefit
import time, numpy as np

def estimate_accuracy(strategy, task_type):
    """Rough accuracy ranges from published benchmarks (GSM8K, MMLU, etc)."""
    estimates = {
        "zero_shot": {"reasoning": 0.55, "classification": 0.75, "extraction": 0.70},
        "few_shot_3": {"reasoning": 0.65, "classification": 0.85, "extraction": 0.82},
        "few_shot_5": {"reasoning": 0.68, "classification": 0.88, "extraction": 0.85},
        "cot": {"reasoning": 0.82, "classification": 0.88, "extraction": 0.85},
        "cot_self_consistency": {"reasoning": 0.88, "classification": 0.90, "extraction": 0.88},
    }
    return estimates.get(strategy, {}).get(task_type, 0.0)

def latency_overhead_us(strategy, output_tokens=100):
    overhead = {
        "zero_shot": 0,
        "few_shot_3": 150 * 1000,  # 150ms extra context processing
        "few_shot_5": 250 * 1000,
        "cot": 500 * 1000 + output_tokens * 10 * 1000,  # reasoning + output
        "cot_self_consistency": (500 * 1000 + output_tokens * 10 * 1000) * 3,
    }
    return overhead.get(strategy, 0)

# Decision: 10K QPS, p95 < 150ms
for strat in ["zero_shot", "few_shot_3", "few_shot_5", "cot"]:
    acc = estimate_accuracy(strat, "classification")
    lat = latency_overhead_us(strat) / 1000  # ms
    print(f"{strat:25s}  acc={acc:.0%}  latency={lat:.0f}ms  "
          f"p95_ok={'YES' if lat < 150 else 'NO'}")

# Production prompt registry — versioning, A/B, monitoring
import json, hashlib, time
from dataclasses import dataclass

@dataclass
class PromptVersion:
    content: str
    version: str
    created_at: float
    hash: str = ""

    def __post_init__(self):
        self.hash = hashlib.sha256(self.content.encode()).hexdigest()[:16]

class PromptRegistry:
    """Stores prompt versions and manages A/B rollout."""
    def __init__(self):
        self.versions: dict[str, PromptVersion] = {}
        self.rollouts: dict[str, dict] = {}  # prompt_key -> rollout config

    def register(self, key: str, content: str, version: str):
        pv = PromptVersion(content=content, version=version, created_at=time.time())
        self.versions[f"{key}@{version}"] = pv

    def start_rollout(self, key: str, version: str, target_pct: float):
        """Gradual rollout with canary."""
        self.rollouts[key] = {
            "version": version,
            "target_pct": target_pct,
            "current_pct": 0.05,  # Start at 5%
            "started_at": time.time(),
        }

    def get_prompt(self, key: str, user_id: str) -> PromptVersion:
        """Determine which prompt version a user gets (consistent hashing)."""
        rollout = self.rollouts.get(key)
        if rollout:
            bucket = int(hashlib.md5(user_id.encode()).hexdigest(), 16) % 100
            if bucket < rollout["current_pct"] * 100:
                return self.versions[f"{key}@{rollout['version']}"]
        # Default: use latest stable
        default = f"{key}@stable"
        return self.versions.get(default, PromptVersion("", "none", time.time()))
